
-- 1. 매너온도 구하는 함수
CREATE OR REPLACE FUNCTION FN_GET_MANNER(P_USER_ID NUMBER)
	RETURN NUMBER
IS 
    V_ORIGIN_TEMP NUMBER := 36.5;
	V_TEMP NUMBER;
    
BEGIN	
	SELECT NVL(SUM(SCORE),0)
	INTO V_TEMP
	FROM MANNER_HISTORY
	WHERE USER_ID = P_USER_ID;

	RETURN V_TEMP + V_ORIGIN_TEMP;
END;


SELECT *
FROM MANNER_HISTORY










-- 전체 유저 매너온도 조회
SELECT USER_ID ,FN_GET_MANNER(USER_ID) AS MANNER_TEMP
FROM MANNER_HISTORY;












